void constructPalin(string str, int len) {
    str = list(str);
    int i = -1;
    int j = len;
    while (i < j) {
        i++;
        j--;
        if (str[i] == str[j] && str[i] != '*') {
            continue;
        }
        else if (str[i] == str[j] && str[i] == '*') {
            str[i] = 'a';
            str[j] = 'a';
            continue;
        }
        else if (str[i] == '*') {
            str[i] = str[j];
            continue;
        }
        else if (str[j] == '*') {
            str[j] = str[i];
            continue;
        }
        cout << "Not Possible" << endl;
        return "";
    }
    cout << "Palindrome: " << ''.join(str) << endl;
}

