string decimalToBinary(double num, int k_prec) {
  string binary = "";
  int Integral = int(num);
  double fractional = num - Integral;
  while (Integral > 0) {
    int rem = Integral % 2;
    binary += to_string(rem);
    Integral /= 2;
  }
  binary = binary.substr(0, binary.length() - 1);
  binary += ".";
  while (k_prec > 0) {
    fractional *= 2;
    int fract_bit = int(fractional);
    if (fract_bit == 1) {
      fractional -= fract_bit;
      binary += "1";
    } else {
      binary += "0";
    }
    k_prec--;
  }
  return binary;
}

