        count[i] = 0;
        if (digits[i - 1] > '0')
            count[i] = count[i - 1];
        if (digits[i - 2] == '1' || (digits[i - 2] == '2' && digits[i - 1] < '7'))
            count[i] += count[i - 2];
    }
    return count[n];
