    for (int i = 0; i <= n; i++) {
        lis[i] = 1;
    }
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (arr[i] > arr[j] && lis[i] < lis[j] + 1) {
                lis[i] = lis[j] + 1;
            }
        }
    }
    int lds[n+1];
    for (int i = 0; i <= n; i++) {
        lds[i] = 1;
    }
    for (int i = n - 2; i >= 0; i--) {
        for (int j = i + 1; j < n; j++) {
            if (arr[i] > arr[j] && lds[i] < lds[j] + 1) {
                lds[i] = lds[j] + 1;
            }
        }
    }
    int maximum = lis[0] + lds[0] - 1;
    for (int i = 1; i < n; i++) {
        maximum = max(maximum, lis[i] + lds[i] - 1);
    }
    return maximum;
}

