{
    int factorCount[n+1];
    bool prime[n+1];
    for(int i=0;i<n+1;i++)
    {
        factorCount[i]=0;
        prime[i]=true;
    }
    for(int i=2;i<n+1;i++)
    {
        if(prime[i]==true)
        {
            factorCount[i]=1;
            for(int j=i*2;j<n+1;j+=i)
            {
                factorCount[j]+=1;
                prime[j]=false;
            }
        }
