    int positive = 0;
    int negative = 1;
    while (true) {
        while (positive < size && arr[positive] >= 0) {
            positive += 2;
        }
        while (negative < size && arr[negative] <= 0) {
            negative += 2;
        }
        if (positive < size && negative < size) {
            std::swap(arr[positive], arr[negative]);
        } else {
            break;
        }
    }
}

