    for (int i = 0; i <= m; i++)
    {
        for (int j = 0; j <= n; j++)
        {
            if (i == 0 || j == 0)
            {
                T[i][j] = 0;
            }
            else if (i < j)
            {
                T[i][j] = 0;
            }
            else if (j == 1)
            {
                T[i][j] = i;
