    for(i = 0; i < 2; i++)
    {
        for(j = 0; j <= W; j++)
        {
            mat[i][j] = 0;
        }
    }
    int curr = 0, prev = 0;
    for(i = 0; i < n; i++)
    {
        if(i % 2 == 0)
        {
            curr = 1;
            prev = 0;
        }
        else
        {
            curr = 0;
            prev = 1;
        }
        for(j = 0; j <= W; j++)
        {
            if(wt[i] <= j && j - wt[i] < W)
            {
                mat[curr][j] = max(val[i] + mat[prev][j - wt[i]], mat[prev][j]);
            }
            else
            {
                mat[curr][j] = mat[prev][j];
            }
        }
    }
    if(n % 2 == 0)
    {
        return mat[0][W];
    }
    else
    {
        return mat[1][W];
    }
}

