{ 
    bool subset[n + 1][sum + 1]; 
    for (int i = 0; i <= n; i++) 
        subset[i][0] = true; 
    for (int i = 1; i <= sum; i++) 
        subset[0][i] = false; 
    for (int i = 1; i <= n; i++) { 
        for (int j = 1; j <= sum; j++) { 
            if (j < arr[i - 1]) 
                subset[i][j] = subset[i - 1][j]; 
            if (j >= arr[i - 1]) 
                subset[i][j] = subset[i - 1][j] 
